import json, base64, sys

fixes = {
168: {"thoughts": [
{"title":"Из деревни в Нью-Йорк с 4 центами в кармане","example":"В 1884 году Тесла приехал в Америку с рекомендательным письмом к Томасу Эдисону. В кармане — четыре цента, стихи собственного сочинения и сломанный прибор. Эдисон, прочитав письмо, произнёс знаменитую фразу: я знал двух великих людей — вы один из них. Тесла начал работать в его компании. Он не знал языка, не знал города, не имел денег — единственным активом были идеи и абсолютная вера в их ценность. Большинство людей в такой ситуации вернулись бы назад или остались на вторых ролях у знаменитого покровителя. Тесла выбрал другое: пошёл вперёд, потому что внутренняя цель была сильнее страха и бедности. Этот первый шаг с пустыми карманами и переполненной идеями головой определил всю историю мировой электрификации.","life":""},
{"title":"Война токов: Эдисон против Теслы","example":"Эдисон продвигал постоянный ток и пообещал Тесле 50 000 долларов за улучшение его двигателей. Когда работа была выполнена и Тесла потребовал оплаты, Эдисон ответил: Тесла, вы не понимаете американского юмора. Деньги выплачены не были. Тесла уволился и открыл собственную лабораторию. Началась война токов — одно из жесточайших технологических противостояний XIX века. Эдисон публично казнил животных переменным током, чтобы доказать его опасность. Но Тесла и Вестингаус победили: переменный ток осветил Всемирную выставку в Чикаго 1893 года. Сегодня весь мир работает на переменном токе — это победа человека, которого предали и которому не заплатили. Иногда предательство партнёра становится точкой рождения чего-то большего.","life":""},
{"title":"300 патентов — и смерть в долг","example":"За свою жизнь Тесла получил около 300 патентов в 26 странах. Он изобрёл переменный ток, радио, флуоресцентное освещение, беспроводную передачу энергии — технологии, на которых держится современная цивилизация. Однако умер в январе 1943 года в нью-йоркской гостинице Нью-Йоркер, в долгах и в полном одиночестве. Его личное имущество не заслуживало описи: несколько старых вещей, дневники, кормушки для голубей. Финансово Тесла был катастрофически неуспешен — он не умел превращать изобретения в деньги и жертвовал гонорарами ради идеи. Человек, давший миру электричество, умер без него. Это трагедия и урок одновременно: гений сам по себе не гарантирует ни благополучия, ни признания при жизни.","life":""},
{"title":"Маниакальная чистота и голуби как семья","example":"Тесла страдал от целого ряда навязчивых ритуалов. Он не мог сесть за стол, не вычислив объём каждого блюда. Ненавидел жемчуг, круглые предметы и женские украшения с камнями. Перед каждым глотком еды должен был совершить строго определённое число движений. В последние годы жизни главной привязанностью стали голуби — он кормил их каждый день на улицах Нью-Йорка и тратил последние сбережения на лечение больной птицы. К ней я испытывал чувства, которых не испытывал ни к кому из людей, — признавался Тесла. Эти странности не слабость — они показывают, что гений и человеческая уязвимость всегда идут рядом. Великие умы нередко платят за свой дар высокую личную цену, и Тесла заплатил её сполна.","life":""},
{"title":"Башня Ворденклиф: мечта, которую сломали","example":"В 1901 году Тесла начал строительство башни Ворденклиф на Лонг-Айленде — системы беспроводной передачи энергии по всему миру. Его цель была радикальной: дать бесплатное электричество каждому человеку на планете. Инвестор Дж. П. Морган финансировал проект, но когда осознал, что бесплатная энергия не принесёт прибыли, отозвал деньги. Строительство остановилось. В 1917 году башню взорвали — официально из-за опасений шпионажа в военное время. Тесла потерял всё: деньги, недвижимость, мечту. Идея беспроводной энергии жива до сих пор — современные учёные продолжают её разрабатывать. Башню убили, идею — нет. Иногда мечты, которые разрушают при жизни, реализуют другие через столетие.","life":""},
{"title":"Фотографическая память и мысленные эксперименты","example":"Тесла обладал феноменальной фотографической памятью: однажды прочитанную книгу он помнил дословно спустя десятилетия. Мог воспроизводить поэмы на нескольких языках и удерживать в уме объёмные математические таблицы. Но главным инструментом была способность проводить полные мысленные эксперименты — без бумаги и схем. Он конструировал двигатели в воображении, прокручивал их работу неделями, выявлял дефекты и вносил исправления — и только после этого приступал к физическому воплощению. Ни один мысленный прототип не нуждался в доработке: всё работало с первого раза. Это не мистика — это предельная концентрация, развитая с детства. Тесла доказал: воображение — не враг точной науки, а её самый мощный и недооценённый инструмент.","life":""},
{"title":"Украденное радио","example":"В 1895 году Тесла запатентовал принципы радиопередачи, однако пожар в его лаборатории уничтожил все прототипы. Пока он восстанавливался, итальянский инженер Гульельмо Маркони в 1901 году передал первый трансатлантический радиосигнал и получил мировую славу. В 1909 году Маркони присудили Нобелевскую премию. Тесла подал в суд, но не имел средств для полноценной защиты. Лишь в 1943 году — спустя несколько месяцев после его смерти — Верховный суд США признал патенты Теслы приоритетными и аннулировал патент Маркони. Справедливость восторжествовала, когда автора уже не было в живых. История знает немало первопроходцев, чьи открытия присвоили другие, — и Тесла среди них самый известный и несправедливо забытый.","life":""},
{"title":"Эдисон работал 18 часов, Тесла — всю ночь","example":"Эдисон был знаменит своей работоспособностью: четыре часа сна, восемнадцать часов труда ежедневно. Тесла шёл дальше. В лучшие годы он работал с десяти утра до пяти утра следующего дня, семь дней в неделю, без отпусков. Когда коллеги падали от усталости, Тесла продолжал. Он считал сон расточительством и был убеждён, что человеческое тело способно на несравнимо большее. Его производительность была феноменальной: за один вечер он проводил серии экспериментов, на которые у обычного учёного уходили недели. Такой темп обходился дорого: нервные срывы, периоды полного истощения. Но именно он позволил Тесле создать больше, чем любому другому изобретателю своего времени. Цена за гениальность была огромной, и Тесла платил её осознанно.","life":""},
{"title":"Вегетарианец, целибат и мёд","example":"В последние десятилетия жизни Тесла перешёл на строжайшую диету: только молоко, мёд и изредка овощные соки. Стал убеждённым вегетарианцем, считая мясоедение варварством, несовместимым с высоким интеллектом. Алкоголь не употреблял принципиально. При этом в молодости был светским человеком — дружил с Марком Твеном, посещал лучшие рестораны Нью-Йорка. Тесла сознательно выбрал целибат, считая, что творческая энергия не может делиться: либо наука, либо всё остальное. Изобретатель — это монах науки, — говорил он. Это не аскетизм из религиозных побуждений, а рациональный расчёт человека, поставившего работу выше любого другого содержания жизни. Его самоограничение было одновременно жертвой и источником невероятной продуктивности.","life":""},
{"title":"Признание пришло через 100 лет","example":"При жизни Тесла умер в нищете и почти полном забвении. Его имя не упоминалось в учебниках, его патенты были присвоены другими, его слава досталась Маркони и Эдисону. Но время расставило всё по местам. В 1960 году единицу магнитной индукции назвали теслой. Илон Маск назвал свою компанию Tesla Motors — в знак признания вклада изобретателя. Его портрет появился на сербских банкнотах, его именем названы аэропорт в Белграде, кратеры на Луне и Марсе. Сегодня Тесла — культовая фигура, символ гения, которого не поняли современники. Его история учит главному: настоящее признание не всегда приходит при жизни. Иногда нужно столетие, чтобы мир осознал, кто был среди них. И это тоже часть цены великого открытия.","life":""}
]},
169: {"thoughts": [
{"title":"Фермер, который разбирал часы","example":"С раннего детства Форд разбирал всё, что попадалось под руку: часы, инструменты, механизмы. Отец был фермером и хотел, чтобы сын продолжил его дело. Но Форда ферма не интересовала — его притягивали машины. В 16 лет он тайком ушёл из дома в Детройт, чтобы работать на паровой двигатель. Возвращался — и снова уходил. Его неудержимое любопытство к механике было не просто увлечением, а указанием судьбы. Именно это детское желание понять, как всё устроено, привело к созданию конвейерного производства, которое изменило промышленность всего мира. Форд доказал: ранняя страсть — не детская прихоть, а подсказка о том, чем стоит заниматься всю жизнь. Тот, кто слышит её и следует ей, меняет мир.","life":""},
{"title":"Пять провалов до первого успеха","example":"Прежде чем основать Ford Motor Company, Форд потерпел несколько серьёзных деловых неудач. Его первая компания Detroit Automobile Company разорилась. Вторая — Henry Ford Company — закончилась конфликтом с инвесторами, и Форда вынудили уйти из собственного бизнеса. Третья попытка в 1903 году наконец принесла результат. Ему было уже сорок лет. Большинство людей после двух провалов отступили бы и выбрали более надёжный путь. Форд продолжал, потому что понимал: каждое поражение давало новое понимание того, что работает, а что нет. Провал — не приговор, а данные для следующей попытки. Именно эта установка позволила ему создать крупнейшую автомобильную компанию своей эпохи и изменить промышленный облик Америки.","life":""},
{"title":"Конвейер: 12 часов превратились в 93 минуты","example":"До конвейера сборка одного автомобиля занимала около 12 часов — рабочие перемещались вокруг машины с инструментами. В 1913 году Форд внедрил движущийся конвейер на заводе в Хайленд-Парке. Время сборки сократилось до 93 минут. Производительность выросла в восемь раз при тех же рабочих. Идею Форд позаимствовал в чикагских скотобойнях, где туши двигались мимо рабочих на крюках. Он инвертировал принцип: не рабочий к изделию, а изделие к рабочему. Простая идея изменила всю мировую промышленность. С тех пор конвейерное производство стало основой индустриальной цивилизации и остаётся ею до сегодняшнего дня. Форд не изобрёл автомобиль — он изобрёл способ сделать его доступным для каждого.","life":""},
{"title":"5 долларов в день — революция в зарплатах","example":"В 1914 году Форд объявил, что будет платить рабочим пять долларов в день — вдвое больше стандартной ставки. Весь деловой мир считал его сумасшедшим. Но расчёт был точным: высокая зарплата снизила текучку кадров, повысила производительность и превратила самих рабочих в покупателей автомобилей Ford. Это был первый в истории пример того, что сегодня называют зарплатой выше рынка как конкурентным преимуществом. Форд понял раньше других: рабочий — не просто фактор производства, но и потенциальный клиент. Заплатить ему достаточно, чтобы он мог купить то, что сам производит, — это не благотворительность, а бизнес-стратегия. Она сработала тогда и работает сейчас в компаниях, понявших эту логику.","life":""},
{"title":"Ford T: одна модель, один цвет, миллионы продаж","example":"Форд сделал ставку на одну модель — Ford T — и один цвет — чёрный. Любой цвет, лишь бы он был чёрным, — говорил он. Это решение казалось ограниченным, но именно оно позволило снизить себестоимость до минимума и сделать автомобиль доступным для среднего американца. С 1908 по 1927 год было продано более 15 миллионов Ford T — треть всех автомобилей мира на тот момент. Ford T изменил Америку: дороги, пригороды, образ жизни. Но Форд слишком долго цеплялся за одну модель, пока конкуренты предлагали разнообразие. В итоге General Motors обогнали его. Успех на одном решении не гарантирует успеха навсегда — рынок меняется, и вместе с ним должны меняться даже самые успешные компании.","life":""},
{"title":"Антисемитизм, который нельзя игнорировать","example":"Форд финансировал антисемитскую газету The Dearborn Independent, публиковавшую откровенно расистские материалы, в том числе пересказ Протоколов сионских мудрецов. Эти публикации переводились на несколько языков и распространялись в Европе. Адольф Гитлер открыто восхищался Фордом и держал его портрет в своём кабинете. Сам Форд в 1938 году принял орден Германского орла. История Форда — это история о том, что великие достижения и моральные провалы могут принадлежать одному человеку. Его вклад в промышленность и его антисемитизм — обе части одной биографии, которую нельзя редактировать. Успех не отменяет ответственности за убеждения. Это важно помнить, оценивая наследие любого исторического деятеля.","life":""},
{"title":"История — это чепуха","example":"Форд не любил историю. История — это в основном чепуха, — говорил он открыто. Он не читал книг, не изучал прошлого и не интересовался академическим образованием. В судебном процессе 1919 года адвокаты противника задали ему серию вопросов по американской истории — и он не смог ответить ни на один. Форд не смутился: я нанимаю людей умнее меня по любому конкретному вопросу. Мне не нужно знать всего — мне нужно знать, к кому обратиться. Это не невежество, а принципиальная позиция: он верил в практику, а не в теорию. Его незнание правил освободило от их ограничений и позволило придумать конвейер там, где все остальные видели только проблему скорости и затрат.","life":""},
{"title":"Конкурент, которого он уважал","example":"Уильям Дюрант, основатель General Motors, был главным конкурентом Форда. Их подходы были диаметрально противоположными: Форд — строгий контроль и одна модель, Дюрант — хаотичная экспансия и множество брендов. Форд относился к Дюранту с профессиональным уважением, называя его человеком, который чувствовал автомобильный рынок инстинктивно. В итоге именно GM с их стратегией разнообразия моделей обогнали Ford в 1920-е годы. Форд признал это, хотя и с опозданием. Уважать конкурента — значит учиться у него. Форд понимал это теоретически, но не всегда успевал применить на практике. История их соперничества стала учебником о том, как единообразие проигрывает разнообразию при изменении рыночных условий.","life":""},
{"title":"Сын фермера, который ненавидел ферму","example":"Форд вырос на ферме и всю жизнь её ненавидел. Ручной труд, бесконечная зависимость от погоды, отсутствие механики — всё это было для него символом прошлого, которое нужно преодолеть. Именно эта ненависть к ферме стала топливом его промышленной революции. Он хотел освободить людей от изнурительного физического труда — и сделал это через механизацию. Ford T превратил американскую деревню: фермеры получили транспорт, независимость и связь с городом. Ирония в том, что человек, бежавший от фермы, в итоге изменил её облик больше, чем кто-либо другой в истории. Иногда именно то, от чего мы бежим, становится источником наших главных достижений.","life":""},
{"title":"Умер миллиардером — но без наследников дела","example":"Форд умер в 1947 году, оставив многомиллиардное состояние. Но настоящим наследием оказалась компания — которую он построил, но не смог передать в надёжные руки. Его сын Эдсел всю жизнь страдал под давлением отца и умер раньше него. Внук Генри Форд II сумел спасти компанию от банкротства, но только радикально изменив всё, что дед построил. Ford Motor Company выжила, но стала другой. Форд создал инструмент, изменивший мир, но не создал преемника, который сохранил бы его дух. Построить компанию и построить компанию, которая переживёт тебя, — совершенно разные задачи. Это урок для каждого основателя: величие идеи не гарантирует долговечности института.","life":""}
]},
170: {"thoughts": [
{"title":"Непригодный ученик с 1093 патентами","example":"В школе Эдисон продержался лишь три месяца — учитель назвал его непригодным для обучения из-за рассеянности и странных вопросов. Мать забрала его домой и занялась образованием сама. Именно она сказала ему, что он умнее своего учителя — и он нёс это убеждение всю жизнь. К моменту смерти в 1931 году Эдисон получил 1093 патента — рекорд, не побитый по сей день. Его изобретения включают лампочку, фонограф, кинетоскоп и электростанцию. Человек, признанный непригодным, стал самым продуктивным изобретателем в истории человечества. Его история — прямое доказательство того, что школьная оценка не измеряет потенциал. Иногда непригодность — это просто несовместимость с системой, а не с реальностью и будущим.","life":""},
{"title":"Глухота как конкурентное преимущество","example":"Эдисон потерял большую часть слуха в 12 лет — предположительно из-за скарлатины или травмы. Большинство людей восприняли бы это как ограничение. Эдисон превратил его в преимущество. Глухота защищала от шума в лаборатории и позволяла концентрироваться без посторонних звуков. Он говорил, что именно отсутствие слуха научило его мыслить: раз не можешь слышать, начинаешь наблюдать и думать интенсивнее. Эдисон создал фонограф — устройство для записи звука — будучи почти глухим. Это один из самых поразительных парадоксов в истории изобретательства: прибор для сохранения звука создал человек, который его почти не слышал. Ограничение стало источником вдохновения и необычного угла зрения на проблему.","life":""},
{"title":"10 000 способов, которые не работают","example":"Когда Эдисона спросили, как он себя чувствует после тысяч неудачных попыток создать лампочку, он ответил: я не потерпел неудачу, я просто нашёл 10 000 способов, которые не работают. За этой фразой стоит не просто оптимизм, а методология: каждый провальный эксперимент был данными, каждый неработающий материал исключался из дальнейшего поиска. Эдисон подходил к изобретательству как к промышленному процессу — систематическому, масштабному, неостановимому. Он нанимал помощников специально для параллельного тестирования сотен материалов. Провал был частью системы, а не исключением из неё. Именно это превратило его в машину по производству изобретений — результативную и предсказуемую, а не зависящую от случайного вдохновения.","life":""},
{"title":"Фабрика изобретений в Менло-Парке","example":"В 1876 году Эдисон основал в Менло-Парке первую в мире коммерческую лабораторию. Он называл её фабрикой изобретений и обещал выдавать одно маленькое изобретение каждые десять дней и одно большое каждые полгода. В лаборатории работало до 60 человек — механики, химики, математики. Эдисон лично контролировал каждый этап параллельных проектов. Это была принципиально новая модель: изобретение как организованный коллективный труд, а не одинокий гений в мастерской. Здесь появились фонограф, лампочка и электростанция. Менло-Парк стал прообразом всех современных корпоративных исследовательских центров. Эдисон изобрёл не только устройства, но и саму форму организации инноваций в промышленном масштабе.","life":""},
{"title":"Первый патент — и первый урок о рынке","example":"Первый патент Эдисон получил в 22 года — на электромеханический счётчик голосов для Конгресса США. Устройство работало безупречно. Но конгрессмены отказались от него: оказалось, медленный подсчёт голосов политически выгоден — он оставлял время для торга. Эдисон извлёк урок на всю жизнь: изобретение без рынка бесполезно. С тех пор, прежде чем начинать разработку, он задавал один вопрос — кто и за сколько это купит? Этот принцип отличал его от Теслы — гения идей, не думавшего о продаже. Эдисон думал о продаже всегда. Именно это превратило его лабораторию в коммерческое предприятие, а не академическую мастерскую. Великое изобретение без покупателя — это просто дорогой эксперимент.","life":""},
{"title":"Война с Теслой и переменным током","example":"Когда Тесла и Вестингаус начали продвигать переменный ток, Эдисон развернул агрессивную кампанию против него. Он публично казнил кошек, собак и даже слона Топси, пропуская через них переменный ток, чтобы доказать его опасность. Лоббировал законы, запрещающие переменный ток, и добился того, чтобы электрический стул работал именно на нём — называя казнь вестингаусингом. Все усилия оказались напрасны: переменный ток выиграл и стал мировым стандартом. Эдисон так и не признал своей ошибки публично. Эта история показывает: даже величайший изобретатель может стать жертвой собственных убеждений, когда они превращаются в идеологию, а не в гипотезу, которую нужно проверять и при необходимости менять.","life":""},
{"title":"4 часа сна и кот-сторож","example":"Эдисон спал по четыре часа в сутки и держал в лаборатории кота, который будил его, когда заканчивался запланированный отдых. Он не пил алкоголь — считал его ядом для мозга — и почти не ел за рабочим столом. Его рабочий день начинался в полночь и заканчивался поздним утром. Гений — это один процент вдохновения и девяносто девять процентов пота, — его слова, ставшие крылатыми. Эдисон не верил в талант без труда. Он верил в систему: правильный распорядок, правильная команда, правильный вопрос — и результат неизбежен. Его режим дня был не причудой, а точным расчётом: он знал, сколько часов сна минимально необходимо, чтобы мозг работал на максимуме производительности.","life":""},
{"title":"Фонограф: изобретение, которое его самого удивило","example":"В 1877 году Эдисон изобрёл фонограф — устройство для записи и воспроизведения звука. Когда он услышал собственный голос из цилиндра впервые, то был потрясён. Я никогда не был так удивлён в жизни, — написал он позже. Фонограф стал первым изобретением, которое буквально никто не предвидел: до него никому не приходило в голову, что звук можно сохранить. Это было изобретение нового класса — создание принципиально новой возможности, а не улучшение существующей. Фонограф открыл эпоху звукозаписи, музыкальной индустрии и аудиодокументации. Всё, что вы сегодня слышите в наушниках, стриминге и кино, восходит к тому моменту, когда Эдисон с изумлением слушал свой голос из металлического цилиндра.","life":""},
{"title":"Кино: Эдисон создал — и почти уничтожил","example":"В 1891 году Эдисон изобрёл кинетоскоп — первый аппарат для просмотра движущихся изображений. Но вместо того чтобы развивать кино как публичный аттракцион, он запатентовал технологию и начал агрессивно преследовать всех, кто использовал похожие устройства. Его патентный трест контролировал производство и прокат фильмов. Независимые кинематографисты бежали от него на другой конец страны — в Голливуд, где агенты Эдисона не дотягивались. Так родился Голливуд — как бегство от монополии. Эдисон создал кино — и своей жадностью помог создать индустрию, которая его обошла. Это парадокс инноватора: изобретение нередко растёт быстрее, чем его создатель готов позволить.","life":""},
{"title":"Пожар на заводе в 67 лет — и новая фабрика через год","example":"В 1914 году завод Эдисона в Вест-Оранже сгорел дотла. Убытки составили около пяти миллионов долларов. Эдисону было 67 лет. Когда сын прибежал к нему в панике, Эдисон стоял у огня и наблюдал со спокойствием. Где мама? Приведи её — она никогда больше не увидит такого огня. На следующий день он заявил: будем строить заново. Через три недели заводы работали снова. Новый комплекс оказался более современным, чем сгоревший. Этот эпизод раскрывает природу подлинной устойчивости: не отсутствие потерь, а способность принимать их как данность и немедленно двигаться дальше. Эдисон не тратил время на горе — он тратил его на восстановление.","life":""}
]}
}

print(base64.b64encode(json.dumps(fixes, ensure_ascii=False).encode('utf-8')).decode('ascii'))
